B.aiI=new A.b5("Ng\xe3 ba n\xe0y c\xf3 m\xf9i kh\xe9t l\u1ea1, nh\u01b0 tro ng\u01b0\u1eddi ch\u01b0a bao gi\u1edd ngu\u1ed9i.","Qu\u1ef7 gi\u1eef ng\xe3 ba v\u1ed1n l\xe0 c\u1ef1u \u0111\u1ed9i tr\u01b0\u1edfng h\u1ed9 t\u1ed1ng d\xe2n n\u1ea1n. H\u1eafn b\xe1n \u0111\u01b0\u1eddng ch\u1ea1y cho c\u01b0\u1edbp, kh\xf3a l\u1ed1i r\xfat r\u1ed3i ph\xf3ng h\u1ecfa c\u1ea3 \u0111o\xe0n ch\u1ec9 \u0111\u1ec3 c\u01b0\u1edbp b\u1ea1c mua thu\u1ed1c phi\u1ec7n. Trong l\u1edbp tro, ta nh\u1eb7t \u0111\u01b0\u1ee3c chu\u1ed7i h\u1ea1t c\u1ee7a m\u1ed9t b\xe0 l\xe3o; ta ch\xf4n n\xf3 c\u1ea1nh g\u1ed1c c\xe2y ch\xe1y, coi nh\u01b0 tr\u1ea3 l\u1ea1i cho b\xe0 m\u1ed9t n\u01a1i \u0111\u1ec3 \u0111\u01b0\u1ee3c nh\u1edb \u0111\u1ebfn.",null)
B.ahZ=new A.b5("Trong khe \u0111\xe1 vang ti\u1ebfng kh\xf3c tr\u1ebb con, r\u1ed3i l\u1eadp t\u1ee9c bi\u1ebfn th\xe0nh ti\u1ebfng c\xe0o c\u1ea5u \u0111i\xean d\u1ea1i.","Ma v\u1eadt n\xe0y t\u1eebng l\xe0 b\xe9 g\xe1i m\u1ed3 c\xf4i t\xean Y\xean, s\u1ed1ng b\u1eb1ng ngh\u1ec1 g\xf9i c\u1ee7i thu\xea. Em b\u1ecb cha d\u01b0\u1ee3ng \u0111\xe1nh \u0111\u1eadp, b\u1ecb \u0111\xe1m ch\u1ee7 n\u1ee3 x\xe2m h\u1ea1i r\u1ed3i n\xe9m xu\u1ed1ng hang \u0111\u1ec3 x\xf3a d\u1ea5u t\xedch nh\u01b0 m\u1ed9t m\xf3n \u0111\u1ed3 h\u1ecfng. O\xe1n h\u1eadn tr\xf3i linh h\u1ed3n em th\xe0nh qu\u1ef7; ta gom t\u1eebng m\u1ea3nh x\u01b0\u01a1ng r\u01a1i r\u1edbt, kh\u1ea5n cho em \u0111\u01b0\u1ee3c g\u1ecdi \u0111\xfang t\xean m\xecnh, \xedt nh\u1ea5t m\u1ed9t l\u1ea7n cu\u1ed1i tr\u01b0\u1edbc khi \u0111i.",null)
B.aiE=new A.b5("H\u1ebbm l\u1eeda im qu\xe1 m\u1ee9c, ch\u1ec9 c\xf2n ti\u1ebfng chu\xf4ng gi\xf3 treo tr\u01b0\u1edbc m\u1ed9t c\u0103n nh\xe0 b\u1ecf hoang.",'T\xean \xe1c nh\xe2n \u1edf \u0111\xe2y t\u1eebng m\u1edf "nh\xe0 vi\u1ec7c t\u1ed1t", chuy\xean d\u1ee5 thi\u1ebfu n\u1eef ngh\xe8o b\u1eb1ng l\u1eddi h\u1ee9a h\u1ecdc ngh\u1ec1. Sau c\xe1nh c\u1eeda \u0111\xf3ng k\xedn l\xe0 \u0111\u01b0\u1eddng d\xe2y bu\xf4n ng\u01b0\u1eddi, n\u01a1i danh t\xednh b\u1ecb x\xe9 b\u1ecf v\xe0 gia \u0111\xecnh b\u1ecb \u0111\u1ed5 l\u1ed7i r\u1eb1ng con h\u1ecd t\u1ef1 b\u1ecf tr\u1ed1n. Khi h\u1eafn ng\xe3 xu\u1ed1ng, ta ghi t\xean c\xe1c n\u1ea1n nh\xe2n l\xean t\u01b0\u1eddng \u0111\xe1 \u0111\u1ec3 kh\xf4ng ai c\xf2n c\xf3 th\u1ec3 x\xf3a h\u1ecd kh\u1ecfi k\xfd \u1ee9c.',null)
B.aiR=new A.b5('R\u1eebng u linh \u0111\u1ea7y b\xf9a tr\u1ea5n t\xe0, nh\u01b0ng m\xf9i m\xe1u c\u0169 cho th\u1ea5y c\xf3 k\u1ebb \u0111ang che t\u1ed9i \xe1c sau ch\u1eef "tr\u1eeb y\xeau".','K\u1ebb \u0111\u1ed9i m\u0169 \u0111\u1ea1o s\u0129 \u1edf \u0111\xe2y s\u0103n "qu\u1ef7 con" \u0111\u1ec3 l\u1ea5y th\u01b0\u1edfng, nh\u01b0ng "qu\u1ef7 con" th\u1ef1c ra l\xe0 \u0111\xe1m tr\u1ebb lang thang b\u1ecb h\u1eafn \u0111\xf3ng \u1ea5n l\xean tr\xe1n. Ai ph\u1ea3n kh\xe1ng th\xec b\u1ecb tuy\xean l\xe0 t\xe0 v\u1eadt r\u1ed3i x\u1eed ngay t\u1ea1i ch\u1ed7 \u0111\u1ec3 mua ti\u1ebfng thanh cao. Ta ph\xe1 h\u1ebft b\xf9a ng\u1ee5y thi\u1ec7n c\u1ee7a h\u1eafn v\xe0 d\u1ef1ng bia g\u1ed7 cho t\u1eebng \u0111\u1ee9a tr\u1ebb, \u0111\u1ec3 c\xf4ng l\xfd l\u1ea7n \u0111\u1ea7u ti\xean g\u1ecdi ch\xfang b\u1eb1ng th\xe2n ph\u1eadn con ng\u01b0\u1eddi.',null)
B.aiF=new A.b5("Tr\u1ea1i c\u01b0\u1edbp n\xe0y treo ph\xf9 hi\u1ec7u t\xf4ng m\xf4n c\u0169 c\u1ee7a ta, nh\u01b0 m\u1ed9t l\u1eddi ch\u1ebf gi\u1ec5u.","Th\u1ee7 l\u0129nh tr\u1ea1i t\u1eebng l\xe0 s\u01b0 huynh ngo\u1ea1i m\xf4n, ng\u01b0\u1eddi t\u1eebng h\u1ee9a s\u1ebd b\u1ea3o v\u1ec7 \u0111\u1ec7 t\u1eed m\u1edbi nh\u1eadp m\xf4n. Trong \u0111\xeam t\xf4ng m\xf4n b\u1ecb di\u1ec7t, h\u1eafn m\u1edf c\u1ed5ng sau \u0111\u1ed5i l\u1ea5y v\xe0ng v\xe0 m\u1ea1ng s\u1ed1ng c\u1ee7a ri\xeang m\xecnh, r\u1ed3i nhi\u1ec1u n\u0103m sau quay l\u1ea1i s\u0103n ch\xednh nh\u1eefng k\u1ebb s\u1ed1ng s\xf3t \u0111\u1ec3 b\u1ecbt mi\u1ec7ng. Ta kh\xf4ng gi\u1ebft h\u1eafn v\xec h\u1eadn c\u0169, ta h\u1ea1 h\u1eafn v\xec nh\u1eefng ng\u01b0\u1eddi \u0111\xe3 tin sai m\u1ed9t k\u1ebb kho\xe1c \xe1o ngh\u0129a kh\xed.",null)
B.aiu=new A.b5("H\u1ed3 ng\u1ecdc ph\u1ea3n chi\u1ebfu m\u1ed9t b\xf3ng ng\u01b0\u1eddi c\xf5ng r\xecu, c\u1ee9 \u0111i v\xf2ng quanh b\u1edd n\u01b0\u1edbc kh\xf4ng bi\u1ebft m\u1ec7t.","T\u01b0\u1edfng l\xe0 y\xeau qu\xe1i, h\xf3a ra \u0111\xf3 l\xe0 m\u1ed9t l\xe3o ti\u1ec1u m\u1ea5t tr\xed v\xec t\u1ef1 tr\xe1ch. N\u0103m x\u01b0a l\xe3o b\u1ecf ch\u1ea1y khi c\u01b0\u1edbp t\u1edbi l\xe0ng, \u0111\u1ec3 ch\xe1u g\xe1i b\u1ecb b\u1eaft \u0111i v\xe0 kh\xf4ng bao gi\u1edd tr\u1edf l\u1ea1i; h\u1ed1i h\u1eadn bi\u1ebfn l\xe3o th\xe0nh linh th\u1ec3 d\u1eef d\u1eb1n v\u1edbi b\u1ea5t c\u1ee9 ai c\u1ea7m ki\u1ebfm. Ta kh\xf4ng ch\u1ec9 ch\xe9m, ta ng\u1ed3i l\u1ea1i nghe l\xe3o k\u1ec3 h\u1ebft m\u1ed9t \u0111\u1eddi d\u1edf dang r\u1ed3i gi\xfap l\xe3o d\u1ef1ng m\u1ed9 gi\xf3 cho \u0111\u1ee9a ch\xe1u, \u0111\u1ec3 l\xe3o c\xf3 th\u1ec3 ng\u1eebng \u0111i v\xf2ng trong n\u1ed7i \xe2n h\u1eadn.",null)
