B.ai0=new A.b5("Gi\u1eefa t\xe0n t\xedch c\xf3 chi\u1ebfc n\xf4i ch\xe1y \u0111en \u0111\u01b0\u1ee3c gi\u1eef s\u1ea1ch b\u1ea5t th\u01b0\u1eddng, nh\u01b0 c\xf3 ng\u01b0\u1eddi ng\xe0y n\xe0o c\u0169ng lau.",'N\u1eef qu\u1ef7 n\u01a1i n\xe0y t\u1eebng l\xe0 m\u1ed9t ng\u01b0\u1eddi m\u1eb9 b\u1ebf con ch\u1ea1y lo\u1ea1n. Qu\xe2n l\u1ec7nh phong t\u1ecfa \u0111\xe3 kh\xf3a c\u1ed5ng th\xe0nh, \u0111\u1ee9a b\xe9 ch\u1ebft trong v\xf2ng tay m\u1eb9 ngay tr\u01b0\u1edbc khi vi\u1ec7n binh t\u1edbi, c\xf2n vi\xean quan ch\u1ec9 n\xf3i: "hy sinh l\xe0 c\u1ea7n thi\u1ebft". Ta \u0111\xe1nh b\u1ea1i o\xe1n linh kh\xf4ng ph\u1ea3i \u0111\u1ec3 ph\u1ee7 nh\u1eadn n\u1ed7i \u0111au c\u1ee7a b\xe0, m\xe0 \u0111\u1ec3 c\u1eaft \u0111\u1ee9t d\xe2y x\xedch khi\u1ebfn n\u1ed7i \u0111au \u1ea5y ti\u1ebfp t\u1ee5c gi\u1ebft nh\u1eefng ng\u01b0\u1eddi v\xf4 t\u1ed9i kh\xe1c.',null)
B.aj_=new A.b5("M\u1ed9t quan ph\u1ee5c r\xe1ch \u0111\u1ee9ng gi\u1eefa l\u1eeda, tay v\u1eabn c\u1ea7m c\xe2n c\xf4ng l\xfd m\xe9o m\xf3.","K\u1ebb n\xe0y t\u1eebng l\xe0 tri huy\u1ec7n n\u1ed5i ti\u1ebfng thanh li\xeam tr\xean gi\u1ea5y t\u1edd. Ban \u0111\xeam, h\u1eafn b\xe1n \xe1n cho nh\xe0 gi\xe0u, \u0111\u1ea9y ng\u01b0\u1eddi ngh\xe8o v\xe0o kh\u1ed5 sai, c\xf2n thi\u1ebfu n\u1eef \u0111i ki\u1ec7n b\u1ecb b\u1eaft giam ri\xeang \u0111\u1ec3 b\u1ecb l\xe0m nh\u1ee5c r\u1ed3i m\u1ea5t t\xedch kh\xf4ng d\u1ea5u v\u1ebft. L\u01b0\u1ee1i ki\u1ebfm c\u1ee7a ta kh\xf4ng thay t\xf2a \xe1n, nh\u01b0ng \u0111\xeam nay \xedt nh\u1ea5t c\u0169ng ch\u1eb7n \u0111\u01b0\u1ee3c b\xe0n tay t\u1eebng b\xf3p ngh\u1eb9t c\xf4ng l\xfd b\u1eb1ng danh ngh\u0129a lu\u1eadt ph\xe1p.",null)
B.aiM=new A.b5("M\xf9i thu\u1ed1c \u1edf \u0111\xe2y n\u1ed3ng \u0111\u1ebfn ngh\u1eb9n th\u1edf, nh\u01b0 ph\xf2ng ch\u1eefa b\u1ec7nh ch\u01b0a t\u1eebng c\u1ee9u ai.",'Qu\xe1i nh\xe2n n\xe0y t\u1eebng l\xe0 danh y \u0111\u01b0\u1ee3c t\xf4n x\u01b0ng "c\u1ee9u th\u1ebf". \xd4ng ta th\u1eed d\u01b0\u1ee3c m\u1edbi l\xean d\xe2n lao \u0111\u1ed9ng kh\xf4ng ti\u1ec1n, ghi ch\xe9p t\u1ec9 m\u1ec9 c\u01a1n \u0111au c\u1ee7a h\u1ecd r\u1ed3i g\u1ecdi \u0111\xf3 l\xe0 "gi\xe1 ph\u1ea3i tr\u1ea3 cho ti\u1ebfn b\u1ed9". Ta \u0111\u1ed1t s\u1ed5 th\xed nghi\u1ec7m v\xe0 \u0111em t\xean t\u1eebng ng\u01b0\u1eddi b\u1ecb h\u1ea1i kh\u1eafc l\xean bia \u0111\xe1, \u0111\u1ec3 l\u1ecbch s\u1eed nh\u1edb r\u1eb1ng h\u1ecd l\xe0 con ng\u01b0\u1eddi, kh\xf4ng ph\u1ea3i nguy\xean li\u1ec7u cho l\xf2ng ki\xeau ng\u1ea1o.',null)
B.aiq=new A.b5("Trong h\u1ea7m tro c\xf3 ti\u1ebfng h\xe1t ru, nh\u01b0ng l\u1eddi ru c\u1ee9 l\u1eb7p l\u1ea1i \u0111\xfang m\u1ed9t c\xe2u xin l\u1ed7i.","Hai ch\u1ecb em tr\xf4ng coi h\u1ea7m n\xe0y t\u1eebng b\xe1n b\xe1nh ven th\xe0nh. Khi n\u1ea1n \u0111\xf3i t\u1edbi, b\u0103ng \u0111\u1ea3ng \xe9p h\u1ecd pha thu\u1ed1c m\xea v\xe0o \u0111\u1ed3 \u0103n \u0111\u1ec3 b\u1eaft ng\u01b0\u1eddi \u0111em b\xe1n, n\u1ebfu kh\xf4ng s\u1ebd gi\u1ebft \u0111\u1ee9a em \xfat m\u1edbi m\u01b0\u1eddi tu\u1ed5i. H\u1ecd s\u1ed1ng s\xf3t nh\u01b0ng linh h\u1ed3n m\u1ee5c r\u1eefa v\xec t\u1ed9i l\u1ed7i; sau tr\u1eadn n\xe0y, ta kh\xf4ng tuy\xean h\u1ecd v\xf4 t\u1ed9i, ch\u1ec9 ch\u1ecdn cho h\u1ecd m\u1ed9t c\xe1i k\u1ebft \xedt t\xe0n nh\u1eabn h\u01a1n b\xf3ng t\u1ed1i \u0111\xe3 nu\u1ed1t h\u1ecd su\u1ed1t ng\u1ea7n \u1ea5y n\u0103m.",null)
B.aiD=new A.b5("N\u1ec1n \u0111\xe1 \u0111\u1ea7y d\u1ea5u m\xf3ng tay, nh\u01b0 c\xf3 ng\u01b0\u1eddi t\u1eebng c\xe0o \u0111\u1ebfn b\u1eadt m\xe1u \u0111\u1ec3 tho\xe1t ra.","\xc1c qu\u1ef7 canh th\xe1c t\u1eebng l\xe0 cai ng\u1ee5c c\u1ee7a tr\u1ea1i n\xf4 t\xf9. H\u1eafn bi\u1ebfn tra t\u1ea5n th\xe0nh tr\xf2 ti\xeau khi\u1ec3n, b\u1eaft t\xf9 nh\xe2n \u0111\xe1nh nhau t\u1edbi ch\u1ebft \u0111\u1ec3 \u0111\u1ed5i l\u1ea5y b\xe1t ch\xe1o lo\xe3ng, r\u1ed3i ghi l\u1ea1i t\u1eebng ti\u1ebfng k\xeau nh\u01b0 m\u1ed9t b\u1ed9 s\u01b0u t\u1eadp b\u1ec7nh ho\u1ea1n. Ta k\u1ebft li\u1ec5u h\u1eafn gi\u1eefa ch\xednh c\u0103n bu\u1ed3ng tra kh\u1ea3o c\u1ee7a h\u1eafn, \u0111\u1ec3 \xedt nh\u1ea5t n\u01a1i n\xe0y t\u1eeb nay ch\u1ec9 c\xf2n im l\u1eb7ng.",null)
B.aiX=new A.b5("Gi\u1eefa bi\u1ec3n l\u1eeda c\xf3 m\u1ed9t binh gi\xe1p c\xf2n gi\u1eef th\u1ebf qu\u1ef3, nh\u01b0 \u0111ang xin tha th\u1ee9 v\u1edbi ai \u0111\xf3 v\xf4 h\xecnh.",'Ng\u01b0\u1eddi mang gi\xe1p n\xe0y t\u1eebng l\xe0 l\xednh ti\xean phong, b\u1ecb \xe9p ra l\u1ec7nh \u0111\u1ed1t l\xe0ng \u0111\u1ec3 ch\u1eb7n \u0111\u1ecbch. \xd4ng l\xe0m theo qu\xe2n l\u1ec7nh, r\u1ed3i m\u1ed7i \u0111\xeam \u0111\u1ec1u nghe ti\u1ebfng tr\u1ebb con g\u1ecdi m\xecnh l\xe0 "k\u1ebb gi\u1ebft nh\xe0". Ta th\u1eafng tr\u1eadn kh\xf4ng ph\u1ea3i \u0111\u1ec3 ca t\u1ee5ng chi\u1ebfn c\xf4ng, m\xe0 \u0111\u1ec3 kh\u1eafc v\xe0o tim r\u1eb1ng m\u1ec7nh l\u1ec7nh kh\xf4ng bao gi\u1edd l\xe0 c\xe1i c\u1edb \u0111\u1ee7 l\u1edbn cho t\u1ed9i \xe1c.',null)
