B.aiN=new A.b5("N\u01b0\u1edbc \u1edf v\u1ecbnh n\xe0y t\u1ed1i nh\u01b0 m\u1ef1c, nh\u01b0ng trong s\xf3ng v\u1eabn l\u1eabn ti\u1ebfng ai \u0111\xf3 g\u1ecdi m\u1eb9.",'H\u1ea3i qu\u1ef7 v\u1eeba ng\xe3 t\u1eebng l\xe0 th\u1ee3 l\u1eb7n nu\xf4i ba em nh\u1ecf b\u1eb1ng ngh\u1ec1 m\xf2 ng\u1ecdc thu\xea. Ch\u1ee7 n\u1ee3 d\xecm l\xe3i \u0111\u1ebfn c\xf9ng \u0111\u01b0\u1eddng, r\u1ed3i b\u1eaft ch\u1ecb k\xfd kh\u1ebf \u01b0\u1edbc b\xe1n th\xe2n; khi ch\u1ecb ch\u1ed1ng c\u1ef1, b\u1ecdn ch\xfang d\xecm ch\u1ecb xu\u1ed1ng v\u1ef1c nh\u01b0 m\u1ed9t c\xe1ch "x\u1eed l\xfd h\xe0ng l\u1ed7i". Ta ph\xe1 \u1ea5n n\xf4 l\u1ec7 tr\xean c\u1ed5 ch\u1ecb v\xe0 th\u1ea3 chu\u1ed7i h\u1ea1t xu\u1ed1ng bi\u1ec3n, mong linh h\u1ed3n \u1ea5y l\u1ea7n n\xe0y \u0111\u01b0\u1ee3c tr\xf4i v\u1ec1 n\u01a1i c\xf3 ng\u01b0\u1eddi ch\u1edd.',null)
B.aiG=new A.b5("X\xe1c t\xe0u m\u1eafc \u1edf r\u1ea1n san h\xf4 mang c\u1edd c\u1ee9u tr\u1ee3, nh\u01b0ng khoang d\u01b0\u1edbi to\xe0n xi\u1ec1ng s\u1eaft.","Thuy\u1ec1n tr\u01b0\u1edfng n\u01a1i \u0111\xe2y treo c\u1edd nh\xe2n \u0111\u1ea1o \u0111\u1ec3 \u0111\xf3n ng\u01b0\u1eddi ch\u1ea1y n\u1ea1n r\u1ed3i nh\u1ed1t h\u1ecd d\u01b0\u1edbi khoang t\xe0u. Tr\u1ebb em b\u1ecb b\xe1n cho h\u1ea7m m\u1ecf, ph\u1ee5 n\u1eef b\u1ecb \u0111\u1ecbnh gi\xe1 nh\u01b0 h\xe0ng h\xf3a, c\xf2n \u0111\xe0n \xf4ng b\u1ecb \xe9p lao d\u1ecbch cho t\u1edbi ki\u1ec7t s\u1ee9c. Ta ch\xe9m \u0111\u1ee9t s\u1ee3i x\xedch cu\u1ed1i c\xf9ng trong khoang t\u1ed1i v\xe0 \u0111\u1ec3 con t\xe0u ch\xecm \u0111\xfang n\u01a1i n\xf3 t\u1eebng nu\u1ed1t ch\u1eedng bi\u1ebft bao s\u1ed1 ph\u1eadn.",null)
B.aij=new A.b5("\u0110\u1ec1n \u0111\xe1 d\u01b0\u1edbi \u0111\xe1y bi\u1ec3n vang ti\u1ebfng m\xf5, nh\u01b0ng l\u1eddi t\u1ee5ng kinh l\u1ea1i l\xe0 b\u1ea3n \xe1n d\xe0nh cho k\u1ebb y\u1ebfu.",'K\u1ebb t\u1ef1 x\u01b0ng h\xf2a th\u01b0\u1ee3ng tr\u1ea5n h\u1ea3i n\xe0y d\u1ea1y m\xf4n \u0111\u1ed3 r\u1eb1ng \u0111au \u0111\u1edbn l\xe0 con \u0111\u01b0\u1eddng thanh t\u1ea9y. H\u1eafn b\u1eaft tr\u1ebb m\u1ed3 c\xf4i ch\u1ecbu \u0111\xf2n roi, b\u1ecf \u0111\xf3i nhi\u1ec1u ng\xe0y \u0111\u1ec3 "di\u1ec7t d\u1ee5c", r\u1ed3i \u0111\u01b0a ng\u01b0\u1eddi kh\xf4ng ch\u1ecbu n\u1ed5i ra l\xe0m v\u1eadt hi\u1ebfn t\u1ebf cho qu\u1ef7 ng\u01b0. Sau tr\u1eadn, ta treo chu\xf4ng c\u1ee7a \u0111\u1ec1n \u1edf l\u1ed1i v\xe0o v\xe0 kh\u1eafc m\u1ed9t c\xe2u duy nh\u1ea5t: kh\xf4ng c\xf3 gi\xe1o l\xfd n\xe0o h\u1ee3p ph\xe1p h\xf3a vi\u1ec7c h\xe0nh h\u1ea1 con ng\u01b0\u1eddi.',null)
B.ai6=new A.b5("D\xf2ng h\u1ea3i l\u01b0u quanh v\u1ef1c xo\xe1y n\xe0y b\u1ea5t th\u01b0\u1eddng, nh\u01b0 c\xf3 ai kh\xf3c su\u1ed1t ng\xe0n n\u0103m d\u01b0\u1edbi \u0111\xe1y.",'Thi\u1ebfu ni\xean h\xf3a qu\u1ef7 \u1edf \u0111\xe2y t\u1eebng l\xe0 \u0111\u1ee9a tr\u1ebb nh\u1eb7t r\xe1c tr\xean b\u1ebfn c\u1ea3ng. Em b\u1ecb b\u1ecdn luy\u1ec7n thu\u1eadt b\u1eaft l\xe0m v\u1eadt th\u1eed "linh c\u0103n nh\xe2n t\u1ea1o", th\xe2n th\u1ec3 s\u1ed1ng d\u1edf ch\u1ebft d\u1edf r\u1ed3i b\u1ecb v\u1ee9t xu\u1ed1ng v\u1ef1c \u0111\u1ec3 phi tang. Ta kh\xf4ng c\u1ee9u \u0111\u01b0\u1ee3c tu\u1ed5i th\u01a1 c\u1ee7a em, nh\u01b0ng ta c\xf3 th\u1ec3 ch\u1ea5m d\u1ee9t ph\xf2ng th\xed nghi\u1ec7m \u0111\xe3 bi\u1ebfn con ng\u01b0\u1eddi th\xe0nh con s\u1ed1 th\u1ea5t b\u1ea1i.',null)
B.ain=new A.b5("Cung \u0111i\u1ec7n san h\xf4 s\xe1ng r\u1ef1c nh\u01b0 l\u1ec5 h\u1ed9i, nh\u01b0ng ph\xeda sau r\xe8m l\xe0 ti\u1ebfng kh\xf3c b\u1ecb n\xe9n l\u1ea1i.","L\xe3nh ch\xfaa \u0111\xe1y bi\u1ec3n n\u1ed5i ti\u1ebfng h\xe0o ph\xf3ng v\xec th\u01b0\u1eddng ph\xe1t ch\u1ea9n tr\u01b0\u1edbc c\xf4ng ch\xfang. C\u0169ng ch\xednh h\u1eafn m\u1edf nh\u1eefng bu\u1ed5i ti\u1ec7c k\xedn, ch\u1ecdn n\xf4 l\u1ec7 tr\u1ebb tu\u1ed5i l\xe0m tr\xf2 mua vui b\u1ec7nh ho\u1ea1n r\u1ed3i th\u1ee7 ti\xeau x\xe1c b\u1eb1ng qu\xe1i ng\u01b0. Khi h\u1eafn ng\xe3, \xe1nh \u0111\xe8n trong cung v\u1ee5t t\u1eaft, v\xe0 l\u1ea7n \u0111\u1ea7u ti\xean \u0111\xe1m n\xf4 l\u1ec7 b\u01b0\u1edbc ra m\xe0 kh\xf4ng ph\u1ea3i c\xfai \u0111\u1ea7u.",null)
B.ai9=new A.b5("M\u1ed9t con th\xfa bi\u1ec3n gi\xe0 ch\u1eafn l\u1ed1i, m\u1eaft n\xf3 \u0111\u1ecf hoe nh\u01b0 \u0111\xe3 th\u1ee9c canh \u0111i\u1ec1u g\xec qu\xe1 l\xe2u.",'Con qu\xe1i n\xe0y t\u1eebng l\xe0 linh th\xfa h\u1ed9 th\xe0nh, nh\u1eadn l\u1eddi b\u1ea3o v\u1ec7 d\xe2n di c\u01b0 qua v\xf9ng bi\u1ec3n d\u1eef. Khi tri\u1ec1u \u0111\xecnh c\u1eaft vi\u1ec7n tr\u1ee3 v\xe0 b\u1ecf m\u1eb7c c\u1ea3 \u0111o\xe0n thuy\u1ec1n, n\xf3 \u1edf l\u1ea1i m\u1ed9t m\xecnh ch\u1ed1ng h\u1ea3i t\u1eb7c \u0111\u1ebfn ki\u1ec7t s\u1ee9c, r\u1ed3i b\u1ecb g\u1ecdi ng\u01b0\u1ee3c l\xe0 "t\xe0 th\xfa". Ta h\u1ea1 n\xf3 trong n\u01b0\u1edbc m\u1eaft c\u1ee7a nh\u1eefng ng\u01b0\u1eddi s\u1ed1ng s\xf3t; c\xf3 nh\u1eefng tr\u1eadn th\u1eafng kh\xf4ng \u0111em l\u1ea1i h\u1ea3 h\xea, ch\u1ec9 \u0111\u1ec3 nh\u1eafc r\u1eb1ng trung ngh\u0129a c\u0169ng c\xf3 l\xfac b\u1ecb th\u1eddi cu\u1ed9c ph\u1ea3n b\u1ed9i.',null)
